repl("Reading saved CryptPad text", "const frameInfo2 = [];
for (const fr of page.frames()) {
  let txt='';
  try { txt = await fr.locator('body').innerText({timeout:1000}); } catch(e) { txt='ERR '+e.message; }
  if (txt.includes('NPB Japan') || txt.includes('Words:') || fr.url().includes('cryptpad')) frameInfo2.push('FRAME '+fr.url()+'\n'+txt.slice(0,1200).replace(/\n/g,' | '));
}
console.log(frameInfo2.join('\n---\n'));")

repl("Inspecting editor iframe body", "const allFrameDetails1 = [];
let idxF1=0;
for (const fr of page.frames()) {
  let url = fr.url();
  let txt=''; let html='';
  try { txt = await fr.locator('body').innerText({timeout:1000}); } catch(e) { txt='ERR'; }
  try { html = await fr.locator('body').evaluate(el => el.innerHTML.slice(0,1000)); } catch(e) { html='ERR '+e.message; }
  allFrameDetails1.push(`IDX ${idxF1++} URL ${url}\nTEXT:${txt.slice(0,300).replace(/\n/g,' | ')}\nHTML:${html.slice(0,500).replace(/\n/g,' ')}`);
}
console.log(allFrameDetails1.join('\n---\n'));")
